ps.pstext:
if !IsFeatureImplemented(FEAT_CPA) then EndOfDecode(Decode_UNDEF); end;
let d : integer{} = UInt(Rd);
let n : integer{} = UInt(Rn);
let m : integer{} = UInt(Rm);
let a : integer{} = UInt(Ra);

let operand1 : bits(64) = X{}(n);
let operand2 : bits(64) = X{}(m);
let operand3 : bits(64) = X{}(a);

var result : bits(64);

let product : integer = SInt(operand1) * SInt(operand2);

// Signed and unsigned twos complement arithmetic are equivalent if only a
// fixed number of bits are considered.
result = operand3 - product[63:0];

let overflow : boolean = (product != SInt(product[63:0]));
result = PointerMultiplyAddCheck(result, operand3, overflow);

X{64}(d) = result;
